from pathlib import Path
import json

TRAINING_TEXT = "summer rain begins\nquiet pages turn\nmodel learns text\n"
UNK = "<UNK>"


def build_vocabulary(text):
    vocab = [UNK] + sorted(set(text))
    char_to_id = {char: index for index, char in enumerate(vocab)}
    id_to_char = {index: char for index, char in enumerate(vocab)}
    return vocab, char_to_id, id_to_char


def encode(text, char_to_id):
    unk_id = char_to_id[UNK]
    return [char_to_id.get(char, unk_id) for char in text]


def decode(tokens, id_to_char):
    return "".join(id_to_char[token] for token in tokens)


def main():
    vocab, char_to_id, id_to_char = build_vocabulary(TRAINING_TEXT)
    example_text = "poem"
    example_tokens = encode(example_text, char_to_id)
    decoded_text = decode(example_tokens, id_to_char)

    Path("tokenizer.json").write_text(
        json.dumps({"vocab": vocab, "char_to_id": char_to_id}, ensure_ascii=False, indent=2),
        encoding="utf-8",
    )
    Path("tokenizer_report.json").write_text(
        json.dumps({
            "vocab_size": len(vocab),
            "roundtrip_ok": decoded_text == example_text,
            "unknown_token": UNK,
            "example_text": example_text,
            "example_tokens": example_tokens,
            "decoded_text": decoded_text,
        }, indent=2),
        encoding="utf-8",
    )
    print("Tokenizer artifacts written")


if __name__ == "__main__":
    main()
